funding_file = locals()['var_functions.query_db:12']
docs_file = locals()['var_functions.query_db:11']

with open(docs_file, 'r') as f:
    docs = json.load(f)
with open(funding_file, 'r') as f:
    funding = json.load(f)

# Find park projects completed in 2022
park_projects_completed_2022 = []

for doc in docs:
    text = doc.get('text', '')
    # Simple approach: find documents mentioning park and 2022 completion
    if 'park' in text.lower() and '2022' in text and 'completed' in text.lower():
        lines = text.split('\n')
        for i, line in enumerate(lines):
            if '2022' in line and 'completed' in line.lower():
                for j in range(max(0, i-5), i):
                    prev = lines[j].strip()
                    if prev and 'park' in prev.lower() and len(prev) < 200:
                        park_projects_completed_2022.append(prev)
                        break

park_projects_completed_2022 = list(set(park_projects_completed_2022))

# Match funding
total_funding = 0
for project in park_projects_completed_2022:
    for fund in funding:
        if project.lower() in fund['Project_Name'].lower() or fund['Project_Name'].lower() in project.lower():
            total_funding += int(fund['Amount'])

print('__RESULT__:')
print(json.dumps({'total_funding': total_funding}))"}

{"code": "import json

# Load civic documents
docs_file = locals()['var_functions.query_db:11']
with open(docs_file, 'r') as f:
    documents = json.load(f)

# Find park projects completed in 2022
park_projects_2022 = []

for doc in documents:
    text = doc.get('text', '')
    lower_text = text.lower()

    # Check if document contains park-related projects completed in 2022
    if 'park' in lower_text and 'completed' in lower_text and '2022' in lower_text:
        lines = text.split('\n')

        for i in range(len(lines)):
            line = lines[i].strip()

            # Look for completion statements mentioning 2022
            if '2022' in line and ('completed' in line.lower() or 'construction was completed' in line.lower()):
                # Look backwards to find project name
                project_name = None
                for j in range(max(0, i-5), i):
                    prev_line = lines[j].strip()
                    if prev_line and len(prev_line) > 5 and 'Updates:' not in prev_line:
                        if not any(x in prev_line.lower() for x in ['capital improvement', 'disaster recovery', 'public works', 'commission', 'agenda']):
                            project_name = prev_line
                            break

                if project_name and 'park' in project_name.lower():
                    park_projects_2022.append(project_name)

# Load funding records
funding_file = locals()['var_functions.query_db:12']
with open(funding_file, 'r') as f:
    funding_records = json.load(f)

# Calculate total funding
total_funding = 0
matched_projects = []

for project in park_projects_2022:
    proj_lower = project.lower()
    for fund in funding_records:
        fund_name = fund['Project_Name'].lower()
        if proj_lower == fund_name or proj_lower in fund_name or fund_name in proj_lower:
            amount = int(fund['Amount'])
            total_funding += amount
            matched_projects.append({
                'project': project,
                'funding_record': fund['Project_Name'],
                'amount': amount
            })

result = {
    'total_funding': total_funding,
    'matched_count': len(matched_projects),
    'matched_projects': matched_projects
}

print('__RESULT__:')
print(json.dumps(result))"}

